// ---- User Input Handling ----

// ---- Input state ----
data class FormState(
    val username: String = "",
    val password: String = "",
    val email: String = "",
    val age: String = "",
    val isSubmitting: Boolean = false,
    val error: String? = null
)

// ---- Input screen ----
@Composable
fun InputScreen() {
    var state by remember { mutableStateOf(FormState()) }

    Scaffold(
        topBar = { TopAppBar { Text("User Input") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            // ---- TextField ----
            OutlinedTextField(
                value = state.username,
                onValueChange = { state = state.copy(username = it) },
                label = { Text("Username") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
                leadingIcon = { Icon(Icons.Default.Person, null) }
            )

            // ---- PasswordField ----
            OutlinedTextField(
                value = state.password,
                onValueChange = { state = state.copy(password = it) },
                label = { Text("Password") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
                visualTransformation = PasswordVisualTransformation(),
                leadingIcon = { Icon(Icons.Default.Lock, null) }
            )

            // ---- Email field ----
            OutlinedTextField(
                value = state.email,
                onValueChange = { state = state.copy(email = it) },
                label = { Text("Email") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
                leadingIcon = { Icon(Icons.Default.Email, null) }
            )

            // ---- Number field ----
            OutlinedTextField(
                value = state.age,
                onValueChange = { 
                    if (it.isEmpty() || it.all(Char::isDigit)) {
                        state = state.copy(age = it)
                    }
                },
                label = { Text("Age") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
                leadingIcon = { Icon(Icons.Default.Number, null) },
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
            )

            // ---- Error message ----
            if (state.error != null) {
                Text(
                    text = state.error ?: "",
                    color = MaterialTheme.colorScheme.error,
                    style = MaterialTheme.typography.bodyMedium
                )
            }

            // ---- Submit button ----
            Button(
                onClick = { state = validateForm(state) },
                modifier = Modifier.fillMaxWidth(),
                enabled = !state.isSubmitting
            ) {
                if (state.isSubmitting) {
                    CircularProgressIndicator(
                        modifier = Modifier.size(24.dp),
                        color = MaterialTheme.colorScheme.onPrimary
                    )
                } else {
                    Text("Submit")
                }
            }

            // ---- Clear button ----
            Button(
                onClick = { state = FormState() },
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(
                    containerColor = MaterialTheme.colorScheme.error
                )
            ) {
                Text("Clear")
            }

            // ---- Validation result ----
            if (state.isSubmitting) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp),
                        horizontalAlignment = Alignment.CenterHorizontally
                    ) {
                        Text("Success!", style = MaterialTheme.typography.titleLarge)
                        Text("Username: ${state.username}")
                        Text("Email: ${state.email}")
                        Text("Age: ${state.age}")
                    }
                }
            }
        }
    }
}

// ---- Validation logic ----
fun validateForm(state: FormState): FormState {
    return when {
        state.username.length < 3 ->
            state.copy(error = "Username must be at least 3 characters")

        state.password.length < 6 ->
            state.copy(error = "Password must be at least 6 characters")

        !state.email.contains("@") ->
            state.copy(error = "Invalid email")

        state.age.isNotEmpty() && state.age.toInt() < 0 ->
            state.copy(error = "Age cannot be negative")

        state.isSubmitting -> state.copy(error = null)

        else -> state.copy(
            isSubmitting = true,
            error = null
        )
    }
}

// ---- Input with keyboard options ----
@Composable
fun KeyboardInputExample() {
    var text by remember { mutableStateOf("") }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // ---- Email keyboard ----
        BasicTextField(
            value = text,
            onValueChange = { text = it },
            modifier = Modifier
                .fillMaxWidth()
                .background(
                    MaterialTheme.colorScheme.surfaceVariant,
                    RoundedCornerShape(8.dp)
                )
                .padding(16.dp),
