package com.example.input

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp

@Composable
fun InputForm() {
    var name by remember { mutableStateOf("") }
    var age by remember { mutableStateOf("") }
    var error by remember { mutableStateOf<String?>(null) }
    var submitted by remember { mutableStateOf(false) }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        OutlinedTextField(
            value = name,
            onValueChange = { 
                name = it
                error = null
            },
            label = { Text("Name") },
            modifier = Modifier.fillMaxWidth(),
            isError = error != null && !submitted
        )

        OutlinedTextField(
            value = age,
            onValueChange = { 
                if (it.isEmpty() || it.all(Char::isDigit)) {
                    age = it
                    error = null
                }
            },
            label = { Text("Age") },
            modifier = Modifier.fillMaxWidth(),
            isError = error != null && !submitted
        )

        if (error != null) {
            Text(
                text = error ?: "",
                color = MaterialTheme.colorScheme.error
            )
        }

        Button(
            onClick = {
                submitted = true
                error = when {
                    name.length < 2 -> "Name must be at least 2 characters"
                    age.isEmpty() -> "Age is required"
                    age.toInt() < 0 -> "Age cannot be negative"
                    age.toInt() > 150 -> "Age must be under 150"
                    else -> null
                }
            },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Submit")
        }

        if (submitted && error == null) {
            Card(
                modifier = Modifier.fillMaxWidth(),
                elevation = CardDefaults.cardElevation(4.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text("✅ Success!", style = MaterialTheme.typography.titleLarge)
                    Text("Name: $name")
                    Text("Age: $age")
                }
            }
        }
    }
}
